def test_research():
    root = {}

    with pytest.raises(TypeError):
        research(root, query=None)

    root = {'a': 'a'}
    res = research(root, query=lambda p, k, v: v == 'a')
    assert len(res) == 1
    assert res[0] == (('a',), 'a')

    def broken_query(p, k, v):
        raise RuntimeError()

    with pytest.raises(RuntimeError):
        research(root, broken_query, reraise=True)

    # empty results with default, reraise=False
    assert research(root, broken_query) == []

    # test that different branches with object identical values are
    # still traversed and returned
    literal_tree = {
            "maybe" : ("hello",),
            "another" : ("hello",),
        }

    assert id(literal_tree["maybe"]) == id(literal_tree["another"])
    assert research(
        root=literal_tree,
    ) == [
        ((None,), literal_tree),
        (("maybe",), ("hello",)),
        (("maybe", 0,), "hello"),
        (("another",), ("hello",)),
        (("another", 0,), "hello"),
    ]

